const row = $('Google Sheets Trigger').item.json;

// Skip empty rows
if (!row['Upload Invoice Files (PDF)  '] || !row['Destination Email Address  ']) {
  return [];
}

const rawUrls = row['Upload Invoice Files (PDF)  '] ?? '';
const industry = row['Industry'] ?? '';
const email = row['Destination Email Address  '] ?? '';
const expenseCategories = row['Expense Categories'] ?? '';

const urls = rawUrls.split(',').map(u => u.trim()).filter(u => u.length > 0);

const files = urls.map(url => {
  const match = url.match(/id=([a-zA-Z0-9_-]+)/);
  const fileId = match ? match[1] : null;
  return { fileId, url, industry, email, expenseCategories };
});

return files.map(f => ({ json: f }));

const binaryData = $('Download File').item.binary.data;
const base64 = binaryData.data;
const mimeType = binaryData.mimeType ?? 'application/pdf';

const isImage = mimeType.startsWith('image/');
const finalMimeType = isImage ? mimeType : 'application/pdf';

const industry = $('Get File IDs').item.json.industry;
const email = $('Get File IDs').item.json.email;
const expenseCategories = $('Get File IDs').item.json.expenseCategories;

const geminiBody = JSON.stringify({
  contents: [{
    parts: [
      {
        inlineData: {
          mimeType: finalMimeType,
          data: base64
        }
      },
      {
        text: `You are an invoice data extraction assistant. The company submitting this invoice operates in the ${industry} industry.\n\nExtract all invoice data and return ONLY valid JSON with these fields:\n- invoice_no\n- supplier_name\n- date_of_invoice (YYYY-MM-DD format)\n- products (return as a JSON array, one entry per line item. Each entry is a string of the product/service name)\n- type_of_expenses (classify into ONLY one of these exact categories: ${expenseCategories}. Pick the closest match.)\n\nReturn a single JSON object. No markdown, no explanation.`
      }
    ]
  }],
  generationConfig: {
    maxOutputTokens: 8192
  }
});

return [{
  json: {
    geminiBody,
    industry,
    email,
    expenseCategories,
    mimeType: finalMimeType
  }
}];

const raw = $('Gemini Vision OCR').item.json.candidates[0].content.parts[0].text;
const cleaned = raw.replace(/```json|```/g, '').trim();
const inv = JSON.parse(cleaned);

const industry = $('Get File IDs').item.json.industry;
const email = $('Get File IDs').item.json.email;
const expenseCategories = $('Get File IDs').item.json.expenseCategories;

// Handle products — could be array or comma-separated string
let products = [];
if (Array.isArray(inv.products)) {
  products = inv.products;
} else if (typeof inv.products === 'string') {
  products = inv.products.split(',').map(p => p.trim()).filter(p => p.length > 0);
}

// If no products found, still write one row
if (products.length === 0) {
  products = ['UNKNOWN'];
}

// Return one item per product
return products.map(product => ({
  json: {
    timestamp:        new Date().toISOString(),
    industry:         industry,
    email:            email,
    invoice_no:       inv.invoice_no       ?? 'UNKNOWN',
    supplier_name:    inv.supplier_name    ?? 'UNKNOWN',
    date_of_invoice:  inv.date_of_invoice  ?? '',
    product:          product,
    type_of_expenses: inv.type_of_expenses ?? ''
  }
}));
